DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM pg_type t JOIN pg_namespace n ON n.oid = t.typnamespace WHERE n.nspname = current_schema() AND t.typname = 'TranscriptJobStatus') THEN CREATE TYPE "template"."TranscriptJobStatus" AS ENUM ('Pending', 'Processing', 'Completed', 'Failed', 'Partial failure'); END IF; END $$;

DO $$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema = current_schema() AND table_name = 'TranscriptJob') THEN EXECUTE 'ALTER TABLE "template"."TranscriptJob" ADD COLUMN IF NOT EXISTS "faculty_id" INTEGER'; IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = current_schema() AND table_name = 'TranscriptJob' AND column_name = 'student_id') THEN EXECUTE 'UPDATE "template"."TranscriptJob" tj SET "faculty_id" = p."faculty_id" FROM "template"."Student" s JOIN "template"."Program" p ON p."id" = s."program_id" WHERE tj."student_id" = s."user_id" AND tj."faculty_id" IS NULL'; END IF; EXECUTE 'ALTER TABLE "template"."TranscriptJob" ALTER COLUMN "status" DROP DEFAULT'; EXECUTE 'ALTER TABLE "template"."TranscriptJob" ALTER COLUMN "status" TYPE "template"."TranscriptJobStatus" USING (CASE "status"::text WHEN ''Done'' THEN ''Completed'' ELSE "status"::text END)::"template"."TranscriptJobStatus"'; EXECUTE 'ALTER TABLE "template"."TranscriptJob" ALTER COLUMN "status" SET DEFAULT ''Pending''::"template"."TranscriptJobStatus"'; EXECUTE 'ALTER TABLE "template"."TranscriptJob" ALTER COLUMN "faculty_id" SET NOT NULL'; EXECUTE 'ALTER TABLE "template"."TranscriptJob" DROP CONSTRAINT IF EXISTS "TranscriptJob_student_id_fkey"'; EXECUTE 'ALTER TABLE "template"."TranscriptJob" DROP CONSTRAINT IF EXISTS "TranscriptJob_faculty_id_fkey"'; EXECUTE 'ALTER TABLE "template"."TranscriptJob" ADD CONSTRAINT "TranscriptJob_faculty_id_fkey" FOREIGN KEY ("faculty_id") REFERENCES "template"."Faculty"("id") ON DELETE RESTRICT ON UPDATE CASCADE'; EXECUTE 'DROP INDEX IF EXISTS "template"."TranscriptJob_student_id_semester_id_idx"'; EXECUTE 'DROP INDEX IF EXISTS "template"."TranscriptJob_semester_id_faculty_id_idx"'; EXECUTE 'CREATE INDEX "TranscriptJob_semester_id_faculty_id_idx" ON "template"."TranscriptJob"("semester_id", "faculty_id")'; IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema = current_schema() AND table_name = 'TranscriptJob' AND column_name = 'student_id') THEN EXECUTE 'ALTER TABLE "template"."TranscriptJob" DROP COLUMN "student_id"'; END IF; END IF; END $$;
